namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // -------------------------------------------------------
    // FormatPhoneNumber
    // -------------------------------------------------------

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    [DataRow("5551234567", "(555) 123-4567")]
    [DataRow("0000000000", "(000) 000-0000")]
    [DataRow("9876543210", "(987) 654-3210")]
    public void FormatPhoneNumber_MultipleInputs_ReturnsExpected(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPhonePattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // -------------------------------------------------------
    // BuildGreeting
    // -------------------------------------------------------

    [TestMethod]
    public void BuildGreeting_NameOnly_ReturnsDefaultTitle()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson", "Prof.");

        Assert.Contains("Anderson", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhitespaceName_Throws(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // -------------------------------------------------------
    // GenerateSlug
    // -------------------------------------------------------

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  Leading Spaces  ", "leading-spaces")]
    [DataRow("UPPER CASE TITLE", "upper-case-title")]
    [DataRow("Special!@#Characters", "special-characters")]
    [DataRow("multiple   spaces", "multiple-spaces")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_Result_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post Title!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_StartsWithLowercase()
    {
        var result = _formatter.GenerateSlug("About Us Page");

        Assert.StartsWith("about", result);
    }

    [TestMethod]
    public void GenerateSlug_TrailingSpecialChars_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Trailing!!!");

        Assert.EndsWith("trailing", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhitespace_Throws(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // -------------------------------------------------------
    // FormatCurrency
    // -------------------------------------------------------

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(9.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    [DataRow("19.99", "$", "$19.99")]
    [DataRow("0.50", "€", "€0.50")]
    [DataRow("1000.00", "£", "£1000.00")]
    public void FormatCurrency_VariousInputs_ReturnsExpected(
        string amount, string symbol, string expected)
    {
        var result = _formatter.FormatCurrency(decimal.Parse(amount), symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.75m);

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces_MatchesPattern()
    {
        var result = _formatter.FormatCurrency(42.5m, "$");

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }
}

